 1	import * as React from 'react';
 2	import { Button, Popover, PopoverPosition } from '@patternfly/react-core';
 3	
 4	type PopoverStatusProps = {
 5	  statusBody: React.ReactNode;
 6	  onHide?: () => void;
 7	  onShow?: () => void;
 8	  title?: string;
 9	  hideHeader?: boolean;
10	  isVisible?: boolean;
11	  shouldClose?: (hideFunction: any) => void;
12	  popoverPosition?: PopoverPosition;
13	  hasAutoWidth?: boolean;
14	};
15	
16	const PopoverStatus: React.FC<PopoverStatusProps> = ({
17	  hideHeader,
18	  children,
19	  isVisible = null,
20	  shouldClose = null,
21	  statusBody,
22	  title,
23	  onHide,
24	  onShow,
25	  popoverPosition,
26	  hasAutoWidth,
27	}) => {
28	  return (
29	    <Popover
30	      position={popoverPosition || PopoverPosition.right}
31	      headerContent={hideHeader ? null : title}
32	      bodyContent={children}
33	      aria-label={title}
34	      onHide={onHide}
35	      onShow={onShow}
36	      isVisible={isVisible}
37	      shouldClose={shouldClose}
38	      hasAutoWidth={hasAutoWidth}
39	    >
40	      <Button variant="link" isInline>
41	        {statusBody}
42	      </Button>
43	    </Popover>
44	  );
45	};
46	
47	export default PopoverStatus;

